import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life", () => {
  it("should return empty grid for empty input", () => {
    expect(nextGeneration([])).toEqual([]);
  });
  it("should kill a single cell (underpopulation)", () => {
    expect(nextGeneration([[0, 0]])).toEqual([]);
  });
  it.todo("should kill two cells that each have only 1 neighbor");
  it("should have a live cell survive with exactly 2 neighbors", () => {
    // Vertical line of 3 cells: (0,0), (0,1), (0,2)
    // Middle cell (0,1) has 2 neighbors and survives
    expect(nextGeneration([[0, 0], [0, 1], [0, 2]])).toEqual([[0, 1]]);
  });
  it.todo("should have a live cell survive with exactly 3 neighbors");
  it.todo("should kill a live cell with 4 neighbors (overpopulation)");
  it.todo("should create a new cell from reproduction (dead cell with 3 neighbors)");
  it.todo("should transform blinker pattern correctly");
  it.todo("should keep block pattern stable");
});

