it("should have a live cell survive with exactly 3 neighbors", () => {
  // Blinker pattern vertical: (0,0), (0,1), (0,2)
  // But with one extra neighbor at (1,1) for 3 neighbors on center cell
  // Actually simpler: 2x2 square with one corner missing
  // (0,0), (0,1), (1,0) with center (0.5,0.5) would have 3, but we need integer coords
  // Pattern: (0,1), (1,0), (1,1) - cell (1,1) has 2 neighbors, cell (0,1) has 1, cell (1,0) has 1
  // Better: (0,0), (0,1), (1,1) - cell (0,1) and (1,1) and (0,0) form L shape
  // Cell (0,1): neighbors at (0,0), (0,2), (1,1) where (0,0) and (1,1) exist = 2 neighbors
  // Let me use the classic blinker pattern but check middle cell survives with 3
  // Horizontal line: (0,1), (1,1), (2,1)
  // Middle cell (1,1) has neighbors above/below (1,0), (1,2) - that's only 2 from neighbors
  // Wait, with (0,1), (1,1), (2,1), cell (1,1) neighbors are:
  // (0,0), (0,1), (0,2), (1,0), (1,2), (2,0), (2,1), (2,2)
  // Of these, only (0,1) and (2,1) are alive = 2 neighbors
  // For 3 neighbors: (0,1), (1,0), (1,1), (1,2) - a plus/cross pattern
  // Cell (1,1) neighbors: (0,0), (0,1), (0,2), (1,0), (1,2), (2,0), (2,1), (2,2)
  // Alive: (0,1), (1,0), (1,2) = 3 neighbors ✓
  expect(nextGeneration([[0, 1], [1, 0], [1, 1], [1, 2]])).toEqual([[0, 1], [1, 0], [1, 1], [1, 2]]);
});

